import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import api from '../services/api';

const QuestionList = () => {
  const [questions, setQuestions] = useState([]);
  const [isLoading, setIsLoading] = useState(true);
  const [fetchError, setFetchError] = useState(null);

  useEffect(() => {
    let ignore = false;

    const getQuestions = async () => {
      try {
        console.log('QuestionList → fetching /questions');
        const res = await api.get('/questions');

        if (!ignore) {
          console.log('QuestionList → response.data type:', typeof res.data);
          console.log('QuestionList → response.data:', res.data);

          const data = Array.isArray(res.data) ? res.data : [];
          setQuestions(data);
        }
      } catch (err) {
        if (!ignore) {
          console.error('QuestionList → fetch failed', err);
          setFetchError('Cannot load questions right now');
        }
      } finally {
        if (!ignore) {
          setIsLoading(false);
        }
      }
    };

    getQuestions();

    return () => {
      ignore = true;
    };
  }, []);

  // ────────────────────────────────────────────────
  // Render – extremely defensive
  // ────────────────────────────────────────────────

  if (isLoading) {
    return <div style={{ padding: '40px', color: '#0066ff' }}>Loading questions…</div>;
  }

  if (fetchError) {
    return (
      <div style={{ padding: '40px', color: 'red', background: '#fff5f5' }}>
        {fetchError}
        <br />
        <small>(check browser console for more info)</small>
      </div>
    );
  }

  // At this point questions is guaranteed to be an array
  return (
    <div style={{ padding: '20px 0' }}>
      <h3 style={{ margin: '0 0 16px' }}>
        Questions {questions.length > 0 ? `(${questions.length})` : ''}
      </h3>

      {questions.length === 0 ? (
        <div style={{ color: '#666', fontSize: '16px' }}>
          No questions yet.<br />
          <Link to="/ask" style={{ color: '#0077cc' }}>
            Ask the first one →
          </Link>
        </div>
      ) : (
        <div>
          {questions.map((item, index) => {
            // Extra safety for each item
            if (!item || !item._id) return null;

            return (
              <div
                key={item._id || `q-${index}`}
                style={{
                  padding: '12px 0',
                  borderBottom: '1px solid #eee',
                }}
              >
                <Link
                  to={`/questions/${item._id}`}
                  style={{
                    fontSize: '17px',
                    fontWeight: '500',
                    color: '#0066cc',
                    textDecoration: 'none',
                  }}
                >
                  {item.title || '(no title)'}
                </Link>

                <div style={{ marginTop: '4px', color: '#777', fontSize: '14px' }}>
                  Votes: {Number(item.votes) || 0}
                  {item.tags && Array.isArray(item.tags) && item.tags.length > 0 && (
                    <span style={{ marginLeft: '16px' }}>
                      Tags: {item.tags.join(', ')}
                    </span>
                  )}
                </div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
};

export default QuestionList;
